import{_ as e,o,c as i,a0 as r}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"Modelo Operacional Minimo de Navegacao","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/MODELO_OPERACIONAL_MINIMO_DE_NAVEGACAO.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/MODELO_OPERACIONAL_MINIMO_DE_NAVEGACAO.md","lastUpdated":1782593311000}'),l={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/MODELO_OPERACIONAL_MINIMO_DE_NAVEGACAO.md"};function d(n,a,t,c,s,m){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="modelo-operacional-minimo-de-navegacao" tabindex="-1">Modelo Operacional Minimo de Navegacao <a class="header-anchor" href="#modelo-operacional-minimo-de-navegacao" aria-label="Permalink to &quot;Modelo Operacional Minimo de Navegacao&quot;">​</a></h1><p><strong>Status:</strong> Referencia operacional de curto prazo<br><strong>Data:</strong> 2026-03-18</p><p>&gt; Este documento reduz a ambiguidade entre: &gt; - a fronteira conceitual de fluxo em T3/T4 &gt; - e o que o NEXUS atual realmente precisa consolidar antes de qualquer formalizacao mais forte</p><h2 id="proposito" tabindex="-1">Proposito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Proposito&quot;">​</a></h2><p>Definir o menor modelo util de navegacao da janela de contexto no NEXUS atual.</p><p>Ele existe para evitar dois erros:</p><ul><li>reduzir tudo a ranking flat de <code>top_k</code></li><li>tentar instrumentar uma geometria de fluxo antes de consolidar a unidade navegavel</li></ul><h2 id="hipotese-operacional-minima" tabindex="-1">Hipotese operacional minima <a class="header-anchor" href="#hipotese-operacional-minima" aria-label="Permalink to &quot;Hipotese operacional minima&quot;">​</a></h2><p>No NEXUS atual, a navegacao da janela pode ser entendida assim:</p><ol><li>a query encontra sementes locais em <code>T3</code></li><li><code>T4</code> expande a vizinhanca relevante dessas sementes</li><li><code>T2</code> reidrata conteudo, identidade e versao</li><li>o sistema materializa <code>packs</code> coerentes por blob</li><li>a LLM recebe uma janela navegavel formada por blocos coerentes, nao apenas por chunks soltos</li></ol><h2 id="o-que-este-modelo-ainda-nao-faz" tabindex="-1">O que este modelo ainda nao faz <a class="header-anchor" href="#o-que-este-modelo-ainda-nao-faz" aria-label="Permalink to &quot;O que este modelo ainda nao faz&quot;">​</a></h2><ul><li>nao define fluxo como objeto medido</li><li>nao define distancia composta canônica</li><li>nao assume geometria cilindrica, esferica ou helicoidal como implementacao</li><li>nao trata T3 como espaco dinamico derivado do T4</li></ul><p>Essas coisas podem continuar como fronteira de pesquisa. Nao sao prerequisito para o proximo passo do runtime.</p><h2 id="unidade-navegavel" tabindex="-1">Unidade navegavel <a class="header-anchor" href="#unidade-navegavel" aria-label="Permalink to &quot;Unidade navegavel&quot;">​</a></h2><p>A principal lacuna do NEXUS atual nao e a falta imediata de metricas. E a definicao insuficiente da unidade navegavel.</p><p>Por enquanto, a unidade mais defensavel e:</p><ul><li><code>seed</code> como ponto de entrada</li><li><code>pack</code> como unidade minima de contexto coerente</li></ul><p>Isso e melhor do que:</p><ul><li><code>chunk</code> isolado como unidade conceitual final</li></ul><p>E mais prudente do que:</p><ul><li>assumir logo um caminho ou fluxo formal completo</li></ul><h2 id="papel-de-cada-camada-no-curto-prazo" tabindex="-1">Papel de cada camada no curto prazo <a class="header-anchor" href="#papel-de-cada-camada-no-curto-prazo" aria-label="Permalink to &quot;Papel de cada camada no curto prazo&quot;">​</a></h2><h3 id="t3" tabindex="-1">T3 <a class="header-anchor" href="#t3" aria-label="Permalink to &quot;T3&quot;">​</a></h3><ul><li>detector de incidencia local</li><li>encontra sementes por proximidade</li></ul><h3 id="t4" tabindex="-1">T4 <a class="header-anchor" href="#t4" aria-label="Permalink to &quot;T4&quot;">​</a></h3><ul><li>malha minima de expansao</li><li>amplia o bairro relevante da seed</li></ul><h3 id="t2" tabindex="-1">T2 <a class="header-anchor" href="#t2" aria-label="Permalink to &quot;T2&quot;">​</a></h3><ul><li>ancora canonica</li><li>reidrata blob, versao, path e contexto vizinho</li></ul><h3 id="packs" tabindex="-1">Packs <a class="header-anchor" href="#packs" aria-label="Permalink to &quot;Packs&quot;">​</a></h3><ul><li>unidade navegavel minima</li><li>preservam coerencia local</li><li>evitam que a janela seja so uma lista de fragmentos</li></ul><h2 id="perguntas-corretas-antes-de-medir-fluxo" tabindex="-1">Perguntas corretas antes de medir fluxo <a class="header-anchor" href="#perguntas-corretas-antes-de-medir-fluxo" aria-label="Permalink to &quot;Perguntas corretas antes de medir fluxo&quot;">​</a></h2><p>Antes de instrumentar <code>edge_flow</code>, <code>region_density</code> ou <code>query_drift</code>, o projeto precisa responder melhor:</p><ol><li>O que exatamente e um estado navegavel hoje?</li><li>Qual e a menor trajetoria util entre seed e pack?</li><li>Em que ponto a navegacao deixa de ser expansao local e passa a ser caminhada semantica?</li></ol><h2 id="proximo-passo-recomendado" tabindex="-1">Proximo passo recomendado <a class="header-anchor" href="#proximo-passo-recomendado" aria-label="Permalink to &quot;Proximo passo recomendado&quot;">​</a></h2><p>O menor proximo passo compativel com o NEXUS atual e:</p><ol><li>consolidar <code>pack</code> como unidade navegavel minima</li><li>explicitar melhor a relacao <code>seed -&amp;gt; subgrafo local -&amp;gt; pack</code></li><li>so depois disso considerar instrumentacao de fluxo</li></ol><h2 id="relacao-com-os-documentos-de-fronteira" tabindex="-1">Relacao com os documentos de fronteira <a class="header-anchor" href="#relacao-com-os-documentos-de-fronteira" aria-label="Permalink to &quot;Relacao com os documentos de fronteira&quot;">​</a></h2><p>Os documentos abaixo continuam validos, mas como horizonte e nao como backlog imediato:</p><ul><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/GEOMETRIA_DE_FLUXO_T3.html">GEOMETRIA_DE_FLUXO_T3.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/T3_FLUXO_FORMALIZACAO_INICIAL.html">T3_FLUXO_FORMALIZACAO_INICIAL.md</a></li></ul><p>Este documento vem antes deles na ordem de implementacao.</p><h2 id="leituras-de-apoio" tabindex="-1">Leituras de apoio <a class="header-anchor" href="#leituras-de-apoio" aria-label="Permalink to &quot;Leituras de apoio&quot;">​</a></h2><ul><li><a href="/var/home/bruno/NEXUS/docs/CANONICAL_RUNTIME.html">CANONICAL_RUNTIME.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/REFATORACAO_MEMORIA_OPERACIONAL.html">REFATORACAO_MEMORIA_OPERACIONAL.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/CANONICAL_T4.html">CANONICAL_T4.md</a></li></ul>',42)])])}const h=e(l,[["render",d]]);export{p as __pageData,h as default};
